// convex-template/convex/config.ts
import { v } from "convex/values";
import { internalQuery, mutation } from "./_generated/server";
var getConfigs = internalQuery({
  args: { keys: v.array(v.string()) },
  handler: async (ctx, args) => {
    const results = [];
    for (const key of args.keys) {
      const config = await ctx.db.query("tenantConfig").withIndex("by_key", (q) => q.eq("key", key)).first();
      if (config) results.push(config);
    }
    return results;
  }
});
var upsertConfig = mutation({
  args: {
    key: v.string(),
    value: v.string()
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db.query("tenantConfig").withIndex("by_key", (q) => q.eq("key", args.key)).first();
    if (existing) {
      await ctx.db.patch(existing._id, { value: args.value });
    } else {
      await ctx.db.insert("tenantConfig", args);
    }
  }
});
export {
  getConfigs,
  upsertConfig
};

