import { v } from "convex/values";
import { mutation, internalAction, internalQuery } from "./_generated/server";
import { internal } from "./_generated/api";
var registerPushToken = mutation({
  args: {
    userId: v.string(),
    token: v.string(),
    platform: v.union(v.literal("ios"), v.literal("android"))
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db.query("pushTokens").withIndex("by_user", (q) => q.eq("userId", args.userId)).collect();
    for (const doc of existing) {
      await ctx.db.delete(doc._id);
    }
    const id = await ctx.db.insert("pushTokens", {
      userId: args.userId,
      token: args.token,
      platform: args.platform
    });
    return id;
  }
});
var removePushToken = mutation({
  args: {
    userId: v.string()
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db.query("pushTokens").withIndex("by_user", (q) => q.eq("userId", args.userId)).collect();
    for (const doc of existing) {
      await ctx.db.delete(doc._id);
    }
  }
});
var getAllTokens = internalQuery({
  args: {},
  handler: async (ctx) => {
    return await ctx.db.query("pushTokens").collect();
  }
});
var sendOrderNotification = internalAction({
  args: {
    customerName: v.string(),
    total: v.number(),
    itemCount: v.number(),
    orderId: v.string()
  },
  handler: async (ctx, args) => {
    const tokens = await ctx.runQuery(internal.notifications.getAllTokens, {});
    if (tokens.length === 0) {
      return;
    }
    const messages = tokens.map((doc) => ({
      to: doc.token,
      sound: "default",
      title: "New Order!",
      body: `${args.customerName} \u2014 \u20B1${args.total.toFixed(2)} (${args.itemCount} item${args.itemCount !== 1 ? "s" : ""})`,
      data: { orderId: args.orderId }
    }));
    try {
      await fetch("https://exp.host/--/api/v2/push/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(messages)
      });
    } catch (error) {
      console.error("Failed to send push notification:", error);
    }
  }
});
export {
  getAllTokens,
  registerPushToken,
  removePushToken,
  sendOrderNotification
};

